/bin/bash -lc "node - <<'NODE'
const fs=require('fs');
const rows=fs.readFileSync('data/sales.csv','utf8').trim().split('\\n').slice(1).map((s,i)=>{const [order_id,date,region,product,units,unit_price]=s.split(',');return {line:i+2,order_id,date,region,product,units:+units,unit_price:+unit_price,rev:+units*+unit_price}});
const sum=a=>a.reduce((x,y)=>x+y,0);
const total=sum(rows.map(x=>x.rev));
const vals=rows.map(x=>x.rev).sort((a,b)=>a-b);
const median=(vals[14]+vals[15])/2;
for(const key of ['product','region']) {const o={};for(const x of rows)(o[x[key]]??=[]).push(x); console.log(key);for(const [k,v] of Object.entries(o))console.log(k,sum(v.map(x=>x.rev)).toFixed(2),v.map(x=>x.line).join(','));}
console.log({orders:rows.length,total:total.toFixed(2),median:median.toFixed(2),middles:[vals[14],vals[15]],avg:total/rows.length});
NODE"

